<template>
  <div class="common-layout">
    <el-container>
      <el-header>
        <el-menu
          class="menu"
          :default-active="activeIndex"
          mode="horizontal"
          @select="handleSelect"
        >
          <el-menu-item index="1">
            首页
          </el-menu-item>
          <el-menu-item index="2">
            关于我
          </el-menu-item>
        </el-menu>
      </el-header>
      <el-main>
        <router-view />
      </el-main>
      <el-footer>
        <p>&copy; 2024 高华西 个人博客. 保留所有权利.</p>
      </el-footer>
    </el-container>
  </div>
</template>
<script>
import { useRouter } from 'vue-router';
export default {
  name: 'MyHome',
  setup() {
    const router = useRouter();
    const handleSelect = (index) => {
      // 根据 el-menu-item 的 index 来确定跳转的路由
      if (index === '1') {
        router.push('/'); // 跳转到首页
      } else if (index === '2') {
        router.push('/about'); // 跳转到关于页面
      }
    };

    return {
      handleSelect,
    };
  },
  data() {
    return {
      activeIndex: '1',
    }
  }
}
</script>

<style>
@import "element-plus/dist/index.css";  /* 正确引入 Element Plus 的样式 */
</style>